 1→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
 2→import { TypesTagLabel } from '@semparar/design-system-app/src/atomic/molecules/TagLabel/Models';
 3→import { PointsTransaction } from '../../../services/models';
 4→
 5→export const STATUS_COLORS: Record<string, TypesTagLabel> = {
 6→  Pendente: 'highlight',
 7→  Confirmado: 'highlight',
 8→  Enviado: 'success',
 9→  Finalizado: 'success',
10→  Estornado: 'error',
11→  Cancelado: 'alert',
12→};
13→
14→export interface MyOrdersItemPropsView {
15→  myOrders: PointsTransaction[];
16→  emptyImage: string;
17→  isLoading: boolean;
18→  isError: boolean;
19→  modalizeRefFilters: React.RefObject<PropsModalizeRef | null>;
20→  filterGroups: {
21→    label: string;
22→    options: {
23→      label: string;
24→      value: number | string;
25→    }[];
26→  }[];
27→  isRefreshing: boolean;
28→  skeletonCount: number;
29→  screenWidth: number;
30→  formatDate: (iso?: string) => string;
31→  handleGoBack: () => void;
32→  handleOpenFilters: () => void;
33→  handleDetailsOrders: (
34→    transactionId: string,
35→    type?: string,
36→    icon?: string,
37→    status?: string,
38→    origination?: string
39→  )=> void;
40→  handleRefresh: () => void;
41→  handleApplyFilters: (filters: Record<number, unknown>) => void;
42→  initialFilters: Record<number, unknown>;
43→  activeFiltersCount: number;
44→}
