 15→import BasicScreen from '../../atomic/templates/BasicScreen';
 16→import { MyOrdersItemPropsView, STATUS_COLORS } from './models';
 17→
 18→const MyOrdersRewardProgramView: FC<MyOrdersItemPropsView> = ({
 19→  handleGoBack,
 20→  myOrders,
 21→  emptyImage,
 22→  formatDate,
 23→  isLoading,
 24→  isError,
 25→  modalizeRefFilters,
 26→  handleOpenFilters,
 27→  handleDetailsOrders,
 28→  handleRefresh,
 29→  filterGroups,
 30→  isRefreshing,
 31→  skeletonCount,
 32→  screenWidth,
 33→  handleApplyFilters,
 34→  initialFilters,
 35→  activeFiltersCount,
 36→}) => {
 37→  return (
 38→    <BasicScreen
 39→      title="Meus pedidos"
 40→      errorButtonOnPress={() => {}}
 41→      hasScroll
 42→      leftIconOnPress={handleGoBack}
 43→      rightIcon="icon-filter-settings"
 44→      rightIconOnPress={handleOpenFilters}
 45→      hasRightIcon={!!myOrders.length || activeFiltersCount > 0}
 46→      scrollViewProps={{
 47→        refreshControl: (
 48→          <RefreshControl
 49→            onRefresh={handleRefresh}
 50→            refreshing={isRefreshing}
 51→            tintColor={theme.colors.BRAND_BASE_01}
 52→          />
 53→        ),
 54→      }}
 55→    >
 56→      {isLoading && (
 57→        <Box width={screenWidth} mt="nano">
 58→          <FlatList
 59→            testID="loading-list-cashback"
 60→            data={Array.from({ length: skeletonCount })}
 61→            keyExtractor={(_, index) => index.toString()}
 62→            scrollEnabled={false}
 63→            renderItem={() => (
 64→              <Skeleton
 65→                testID="loading-orders-cashback"
 66→                width={screenWidth - 64}
 67→                height={150}
 68→                type="light"
 69→                mt="nano"
 70→                mb="nano"
 71→                mr="medium"
 72→                ml="medium"
 73→                borderRadiusTopLeft="half"
 74→              />
 75→            )}
 76→          />
 77→        </Box>
 78→      )}
 79→
 80→      {isError && (
 81→        <ApiError
 82→          testID="orders-cashback-error"
 83→          title="Algo deu errado!"
 84→          subTitle="Por favor, tente mais tarde"
 85→          isLoading={isLoading}
 86→          hasBackToHome={false}
 87→          onPress={handleGoBack}
 88→        />
 89→      )}
 90→
 91→      {!isLoading && !isError && (
 92→        <FlatList
 93→          data={myOrders}
 94→          renderItem={({ item }) => (
 95→            <Box ml="middle" mr="middle" mt="smaller">
 96→              <CardVehicleTags
 97→                vehicleName={item.description}
 98→                icon={item.icon as PropsIconsNameCore}
 99→                title="Valor em pontos"
100→                titleDescription={String(Math.abs(item.amount))}
101→                date="Data do resgate"
102→                dateNumber={formatDate(item.date)}
103→                statusTitle="Status do pedido"
104→                status={item.status}
105→                ghostButtonText="Exibir detalhes"
106→                onGhostButtonPress={() =>
107→                  handleDetailsOrders(
108→                    item.id,
109→                    item.type,
110→                    item.icon,
111→                    item.status,
112→                    item.origination,
113→                  )
114→                }
115→                type="extended"
116→                typeTag={STATUS_COLORS[item.status] ?? 'alert'}
117→                version="2.0"
118→              />
119→            </Box>
120→          )}
121→          ListEmptyComponent={() => (
122→            <Box align="center" pd="innerLarger" justify="center" mt="larger">
123→              <Image
124→                resizeMode="contain"
125→                /* @ts-ignore `source` is not in the props Of `image` ( ͡° ͜ʖ ͡°) */
126→                source={{ uri: emptyImage }}
127→                width={80}
128→                height={80}
129→              />
130→
131→              {activeFiltersCount > 0 ? (
132→                <Text type="paragraphXXXL" mt="nano" align="center">
133→                  Não há resultados para sua busca
134→                </Text>
135→              ) : (
136→                <>
137→                  <Text type="paragraphXXXL" mt="nano">
138→                    Nenhum pedido feito
139→                  </Text>
140→                  <Text type="paragraphLG" align="center" mt="nano">
141→                    Quando você usar seus pontos em pedidos, eles aparecerão
142→                    aqui.
143→                  </Text>
144→                </>
145→              )}
146→            </Box>
147→          )}
148→        />
149→      )}
150→      {filterGroups.length > 0 && (
151→        <FiltersBottomSheet
152→          modalizeRef={modalizeRefFilters as RefObject<PropsModalizeRef>}
153→          filterGroups={filterGroups}
154→          onApplyFilters={handleApplyFilters}
155→          initialFilters={initialFilters}
156→        />
157→      )}
158→    </BasicScreen>
159→  );
160→};
161→
162→export default MyOrdersRewardProgramView;
