151→function formatDate(iso?: string): string {
152→  if (!iso) return '';
153→  const d = new Date(iso);
154→  const day = String(d.getDate()).padStart(2, '0');
155→  const month = String(d.getMonth() + 1).padStart(2, '0');
156→  const year = d.getFullYear();
157→  return `${day}/${month}/${year}`;
158→}
